 ('1c1b9392-abcb-56a9-b262-7c9759b9e88e','20000000-0000-0000-0000-000000000005','C1',25,$p$Precisión y matiz léxico: das treffende Wort$p$,'#6C3483','auto_stories')
insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('5b7dbf8c-7043-5108-b741-e8c5513d0203','1c1b9392-abcb-56a9-b262-7c9759b9e88e',1,$p$Sinónimos finos y su matiz (betrachten, beobachten, mustern…)$p$,$p$Sinónimos finos y su matiz (betrachten, beobachten, mustern…)$p$,'lesson',15),
 ('0a815c9a-6ff7-5067-844c-868bf4203b78','1c1b9392-abcb-56a9-b262-7c9759b9e88e',2,$p$Colocaciones verbo + sustantivo (eine Entscheidung treffen, Kritik üben)$p$,$p$Colocaciones verbo + sustantivo (eine Entscheidung treffen, Kritik üben)$p$,'lesson',15),
 ('b22f6dbe-42eb-5943-b76d-bf3717a3ca3d','1c1b9392-abcb-56a9-b262-7c9759b9e88e',3,$p$Registros: gehoben, neutral, umgangssprachlich$p$,$p$Registros: gehoben, neutral, umgangssprachlich$p$,'lesson',15),
 ('09640147-2abd-5fbb-aa70-8ca0942d0a27','1c1b9392-abcb-56a9-b262-7c9759b9e88e',4,$p$Precisión: kennen/wissen, scheinbar/anscheinend, Wortwahl fija$p$,$p$Precisión: kennen/wissen, scheinbar/anscheinend, Wortwahl fija$p$,'lesson',15),
 ('9361cc05-e3bb-513a-82e1-d565607b88b8','1c1b9392-abcb-56a9-b262-7c9759b9e88e',5,$p$🏁 Checkpoint Einheit 25$p$,$p$Demuestra que eliges la palabra precisa a nivel C1: distingues sinónimos finos y su connotación (betrachten/beobachten/mustern, wohnen/leben, schätzen/mögen/lieben), dominas las colocaciones verbo+sustantivo (eine Entscheidung treffen, einen Beschluss fassen, Kritik üben), adaptas el registro (gehoben/neutral/umgangssprachlich: Wagen/Auto/Karre, speisen/essen) y evitas errores de precisión (kennen vs wissen, scheinbar vs anscheinend).$p$,'checkpoint',40)
