('f114cf08-0e7e-592d-8339-1bd4da3afa65'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,'C1','reading','match',$p$Relaciona cada verbo con el matiz que aporta. Fíjate en la connotación de cada uno.$p$,$j${"pairs": [{"en": "mustern", "es": "mirar de arriba abajo examinando a alguien"}, {"en": "beobachten", "es": "observar con atención durante un tiempo"}, {"en": "anstarren", "es": "mirar fijamente y de forma descortés"}]}$j$::jsonb,$j${"pairs": [["mustern", "mirar de arriba abajo examinando a alguien"], ["beobachten", "observar con atención durante un tiempo"], ["anstarren", "mirar fijamente y de forma descortés"]]}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$synonyme_sehen_match$p$, $p$reading$p$]),
('68fc5ccc-4213-5f7c-8b1e-7300bde23685'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,'C1','reading','multiple_choice',$p$Elige el verbo que expresa mirar algo con calma y detenimiento, casi con admiración: «Sie blieben stehen, um den Sonnenuntergang in Ruhe zu ___.»$p$,$j${"options": ["betrachten", "erblicken", "bemerken"]}$j$::jsonb,$j${"value": "betrachten"}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$synonyme_betrachten_mc$p$, $p$reading$p$]),
('7f291771-55ec-5f7c-a116-d2ec65d6d2df'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,'C1','writing','cloze',$p$Distingue «wohnen» (residir en un sitio) de «leben» (vivir, existir). Aquí se habla del lugar de residencia: «Seit drei Jahren ___ er in einer kleinen Wohnung am Stadtrand.»$p$,$j${"text": "Seit drei Jahren ___ er in einer kleinen Wohnung am Stadtrand."}$j$::jsonb,$j${"value": "wohnt", "accepted": ["wohnt"]}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$synonyme_wohnen_leben_cloze$p$, $p$writing$p$]),
('43181162-cf18-54f3-ac3d-8518cda50def'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,'C1','listening','listening',$p$Escucha y elige la frase que oíste.$p$,$j${"options": ["Ich schätze seine Ehrlichkeit, auch wenn ich seine Meinung nicht teile.", "Ich bezweifle seine Aufrichtigkeit, weil er seine Meinung ständig ändert.", "Ich bewundere seinen Ehrgeiz, obwohl er seine Pläne selten verrät."], "say": "Ich schätze seine Ehrlichkeit, auch wenn ich seine Meinung nicht teile.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/43181162-cf18-54f3-ac3d-8518cda50def.mp3"}$j$::jsonb,$j${"value": "Ich schätze seine Ehrlichkeit, auch wenn ich seine Meinung nicht teile."}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$synonyme_schaetzen_listening$p$, $p$listening$p$]),
('5c88a4cd-7617-568f-a6b3-631d1daf5eaa'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,'C1','speaking','speaking_read_aloud',$p$Lee en voz alta:$p$,$j${"text": "Man kann ein Bild flüchtig ansehen, doch es zu betrachten verlangt Zeit und Aufmerksamkeit.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/5c88a4cd-7617-568f-a6b3-631d1daf5eaa.mp3"}$j$::jsonb,$j${"expected": "Man kann ein Bild flüchtig ansehen, doch es zu betrachten verlangt Zeit und Aufmerksamkeit."}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$synonyme_speaking$p$, $p$speaking$p$]),
('bd100f3e-0636-5289-8634-4817c03f97fb'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,'C1','reading','match',$p$Relaciona cada verbo con el sustantivo con el que forma la colocación fija correcta en alemán.$p$,$j${"pairs": [{"en": "eine Entscheidung", "es": "treffen"}, {"en": "einen Beschluss", "es": "fassen"}, {"en": "Kritik", "es": "üben"}]}$j$::jsonb,$j${"pairs": [["eine Entscheidung", "treffen"], ["einen Beschluss", "fassen"], ["Kritik", "üben"]]}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$kollokationen_match$p$, $p$reading$p$]),
('6d25351e-3dc4-5399-b126-84cbd97452de'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,'C1','reading','multiple_choice',$p$Elige el verbo que forma la colocación correcta con «eine Entscheidung» (no se calca del español «tomar»): «Der Vorstand muss bis Freitag eine Entscheidung ___.»$p$,$j${"options": ["treffen", "nehmen", "machen"]}$j$::jsonb,$j${"value": "treffen"}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$kollokationen_entscheidung_mc$p$, $p$reading$p$]),
('ffdabed9-d344-58d6-b204-863ef2601138'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,'C1','writing','translation',$p$Traduce usando la colocación culta «Maßnahmen ergreifen» (tomar medidas): «El gobierno tomó medidas drásticas.»$p$,$j${"source": "El gobierno tomó medidas drásticas."}$j$::jsonb,$j${"value": "Die Regierung ergriff drastische Maßnahmen.", "accepted": ["Die Regierung ergriff drastische Maßnahmen", "Die Regierung ergriff drastische Maßnahmen.", "Die Regierung hat drastische Maßnahmen ergriffen.", "Die Regierung hat drastische Maßnahmen ergriffen", "Die Regierung ergriff drastische Massnahmen."]}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$kollokationen_massnahmen_translation$p$, $p$writing$p$]),
('ef271228-bc97-5723-8680-efe4ec58f7ed'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,'C1','listening','listening',$p$Escucha y elige la frase que oíste.$p$,$j${"options": ["An diesem Vorschlag wurde von mehreren Seiten scharfe Kritik geübt.", "Für diesen Vorschlag wurde von allen Seiten großes Lob ausgesprochen.", "Gegen diesen Beschluss hat bislang niemand ernsthafte Einwände erhoben."], "say": "An diesem Vorschlag wurde von mehreren Seiten scharfe Kritik geübt.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/ef271228-bc97-5723-8680-efe4ec58f7ed.mp3"}$j$::jsonb,$j${"value": "An diesem Vorschlag wurde von mehreren Seiten scharfe Kritik geübt."}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$kollokationen_kritik_listening$p$, $p$listening$p$]),
('c9d776af-ef90-5be7-a8eb-5a9ce1f757d4'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,'C1','speaking','speaking_read_aloud',$p$Lee en voz alta:$p$,$j${"text": "Bevor wir einen Beschluss fassen, sollten wir jedes Argument sorgfältig abwägen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/c9d776af-ef90-5be7-a8eb-5a9ce1f757d4.mp3"}$j$::jsonb,$j${"expected": "Bevor wir einen Beschluss fassen, sollten wir jedes Argument sorgfältig abwägen."}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$kollokationen_speaking$p$, $p$speaking$p$]),
('59c6dd05-5cbd-5ca2-8771-eb0893dcde36'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,'C1','writing','cloze',$p$En un menú elegante se usa el registro elevado para «comer/cenar». Completa con el verbo culto (infinitivo): «Die Gäste ___ heute Abend im großen Saal.» (pista: no es «essen»)$p$,$j${"text": "Die Gäste ___ heute Abend im großen Saal."}$j$::jsonb,$j${"value": "speisen", "accepted": ["speisen"]}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$register_gehoben_cloze$p$, $p$writing$p$]),
('51320483-bafc-55c3-8143-9277843f4a80'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,'C1','reading','multiple_choice',$p$Entre amigos, ¿qué palabra pertenece al registro coloquial (y algo despectivo) para «coche»? «Steig ein, meine alte ___ springt sofort an.»$p$,$j${"options": ["Karre", "Limousine", "Kutsche"]}$j$::jsonb,$j${"value": "Karre"}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$register_umgangssprachlich_mc$p$, $p$reading$p$]),
('befc8586-8327-5a2b-94a1-563c566c9b4c'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,'C1','writing','translation',$p$Traduce al registro elevado usando «der Wagen» (coche, culto) y «erwerben» (adquirir, culto): «Se compró un coche nuevo.»$p$,$j${"source": "Se compró un coche nuevo."}$j$::jsonb,$j${"value": "Er erwarb einen neuen Wagen.", "accepted": ["Er erwarb einen neuen Wagen", "Er erwarb einen neuen Wagen.", "Er hat einen neuen Wagen erworben.", "Er hat einen neuen Wagen erworben"]}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$register_gehoben_translation$p$, $p$writing$p$]),
('ba7c967f-d3b1-57ac-a10c-dd6af02450c4'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,'C1','listening','listening',$p$Escucha y elige la frase que oíste.$p$,$j${"options": ["Er hat seine Karre einfach vor meiner Einfahrt abgestellt.", "Sie hat ihr Fahrrad ordentlich hinter dem Haus verstaut.", "Wir haben den Wagen gestern in der Werkstatt abgeholt."], "say": "Er hat seine Karre einfach vor meiner Einfahrt abgestellt.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/ba7c967f-d3b1-57ac-a10c-dd6af02450c4.mp3"}$j$::jsonb,$j${"value": "Er hat seine Karre einfach vor meiner Einfahrt abgestellt."}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$register_listening$p$, $p$listening$p$]),
('0b953c56-cf1d-5384-9267-2afb4e9820b5'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,'C1','speaking','speaking_read_aloud',$p$Lee en voz alta:$p$,$j${"text": "Je nach Situation sagt man «Automobil» im Bericht, «Auto» im Alltag und «Karre» unter Freunden.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/0b953c56-cf1d-5384-9267-2afb4e9820b5.mp3"}$j$::jsonb,$j${"expected": "Je nach Situation sagt man «Automobil» im Bericht, «Auto» im Alltag und «Karre» unter Freunden."}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$register_speaking$p$, $p$speaking$p$]),
('1520f1fa-ca7e-5f78-8250-98f11a72086b'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,'C1','reading','multiple_choice',$p$Distingue «kennen» (estar familiarizado con algo/alguien) de «wissen» (saber un hecho). Elige la forma correcta: «Ich ___ diese Stadt gut, aber ich ___ nicht, wann das Museum öffnet.»$p$,$j${"options": ["kenne … weiß", "weiß … kenne", "kenne … kenne"]}$j$::jsonb,$j${"value": "kenne … weiß"}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$praezision_kennen_wissen_mc$p$, $p$reading$p$]),
('50abca64-2c5f-5387-b100-a3a0955985c1'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,'C1','writing','cloze',$p$«scheinbar» = solo en apariencia (no real); «anscheinend» = por lo visto (probablemente real). Aquí ella SÍ estaba tranquila por lo visto: «___ hatte sie die schlechte Nachricht schon vorher erfahren.»$p$,$j${"text": "___ hatte sie die schlechte Nachricht schon vorher erfahren."}$j$::jsonb,$j${"value": "Anscheinend", "accepted": ["Anscheinend", "anscheinend"]}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$praezision_scheinbar_cloze$p$, $p$writing$p$]),
('33df3dad-cdba-5aa6-ac74-f48387ac2ba6'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,'C1','writing','word_bank',$p$Ordena las fichas para formar: «Er schätzt an ihr vor allem die ehrliche Art.»$p$,$j${"tiles": ["schätzt", "vor allem", "Er", "die", "an ihr", "ehrliche", "Art", "mag"]}$j$::jsonb,$j${"value": "Er schätzt an ihr vor allem die ehrliche Art", "sequence": ["Er", "schätzt", "an ihr", "vor allem", "die", "ehrliche", "Art"]}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$praezision_wortstellung_word_bank$p$, $p$writing$p$]),
('78b1172a-d2a0-54d1-9516-cca8d335ee36'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,'C1','listening','listening',$p$Escucha y elige la frase que oíste.$p$,$j${"options": ["Sein Erfolg war nur scheinbar mühelos, dahinter steckten Jahre harter Arbeit.", "Ihr Aufstieg war tatsächlich mühsam, doch niemand nahm davon Notiz.", "Sein Scheitern war letztlich absehbar, weil er kaum Einsatz zeigte."], "say": "Sein Erfolg war nur scheinbar mühelos, dahinter steckten Jahre harter Arbeit.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/78b1172a-d2a0-54d1-9516-cca8d335ee36.mp3"}$j$::jsonb,$j${"value": "Sein Erfolg war nur scheinbar mühelos, dahinter steckten Jahre harter Arbeit."}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$praezision_listening$p$, $p$listening$p$])
