 ('390a2a3f-442d-56b4-9ebf-2ce396075bfa','20000000-0000-0000-0000-000000000005','C1',29,$p$Hipótesis y modalidad avanzada: Konjunktiv y suposición$p$,'#7D3C98','psychology_alt')
insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('384b2138-8bbe-577c-a6b9-b7431be476cc','390a2a3f-442d-56b4-9ebf-2ce396075bfa',1,$p$Condiciones y deseos irreales (Konjunktiv II)$p$,$p$Condiciones y deseos irreales (Konjunktiv II)$p$,'lesson',15),
 ('fe8d3a8b-811e-546c-a0fd-506145ac80d8','390a2a3f-442d-56b4-9ebf-2ce396075bfa',2,$p$Suposición con modales: dürfte, müsste, will, soll$p$,$p$Suposición con modales: dürfte, müsste, will, soll$p$,'lesson',15),
 ('abc14b6e-c45a-5db9-a19a-df797fbba34c','390a2a3f-442d-56b4-9ebf-2ce396075bfa',3,$p$Estilo indirecto formal (Konjunktiv I)$p$,$p$Estilo indirecto formal (Konjunktiv I)$p$,'lesson',15),
 ('1ad02bb8-e13b-5479-a4be-330ea0a5a482','390a2a3f-442d-56b4-9ebf-2ce396075bfa',4,$p$Comparación irreal: als ob + Konjunktiv$p$,$p$Comparación irreal: als ob + Konjunktiv$p$,'lesson',15),
 ('145ef9e6-b136-579d-8147-b856d87845ea','390a2a3f-442d-56b4-9ebf-2ce396075bfa',5,$p$🏁 Checkpoint Einheit 29$p$,$p$Demuestra que manejas la modalidad a nivel C1: formas condiciones irreales con Konjunktiv II (wäre/hätte + Partizip, würde + Inf), expresas suposición con verbos modales (dürfte = probable, müsste = lógicamente, will/soll = afirmación/rumor), usas el Konjunktiv I del estilo indirecto formal (er sei, er habe) y comparaciones irreales con «als ob» + Konjunktiv.$p$,'checkpoint',40)
