 ('9cf752b0-6512-577e-a52b-0ea3fee14328','504dbd7f-4d9c-52dd-aa65-99660793dd99',2,$p$Voz pasiva ampliada (Vorgangs-, Zustands-, con modal)$p$,$p$Voz pasiva ampliada (Vorgangs-, Zustands-, con modal)$p$,'lesson',15),
